    searchVolume: 5400,
    keywordDifficulty: "low",
    status: "published",
    contentType: "standard",
    tags: ["rush hour", "peak hours", "restaurant operations", "KOT", "table turnover"],
    keywords: ["restaurant rush hour management", "peak hour restaurant tips", "handle busy restaurant"],
    image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=800&h=400&fit=crop",
    imageAlt: "Busy restaurant during rush hour with staff managing tables",
    featured: false,
