    contentType: "standard",
    tags: ["GST", "tax compliance", "GSTR-1", "GSTR-3B", "restaurant India", "tax filing"],
    keywords: ["restaurant GST filing India", "restaurant GST rate", "GSTR-1 restaurant"],
    image: "https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&h=400&fit=crop",
