    contentType: "standard",
    tags: ["Zomato", "Swiggy", "commission", "delivery", "direct ordering", "restaurant revenue"],
    keywords: ["reduce Zomato Swiggy commission", "Zomato commission rate", "direct ordering restaurant India"],
    image: "https://images.unsplash.com/photo-1526367790999-0150786686a2?w=800&h=400&fit=crop",
    imageAlt: "Food delivery apps on smartphone with restaurant owner",
